# Optional HTTP headers for analytics and attribution
response = client.chat.completions.create(
    model='openai/gpt-4o-mini',
    messages=[{'role': 'user', 'content': 'Hi'}],
    extra_headers={
        'HTTP-Referer': 'https://yourapp.com',    # shows in activity dashboard
        'X-Title': 'My App',                      # displayed in logs
    },
)

# Provider preferences — explicit order and routing rules
response = client.chat.completions.create(
    model='openai/gpt-4o',
    messages=[{'role': 'user', 'content': 'Explain RLHF.'}],
    extra_body={
        'provider': {
            'order': ['Anthropic', 'OpenAI'],   # try Anthropic first
            'allow_fallbacks': True,
            'data_collection': 'deny',           # opt out of training data
            'require_parameters': True,          # skip providers missing requested params
        },
    },
)

stream = client.chat.completions.create(
    model='openai/gpt-4o-mini',
    messages=[{'role': 'user', 'content': 'Write a haiku about distributed systems.'}],
    stream=True,
)

for chunk in stream:
    delta = chunk.choices[0].delta.content
    if delta:
        print(delta, end='', flush=True)
print()

import json

tools = [
    {
        'type': 'function',
        'function': {
            'name': 'get_stock_price',
            'description': 'Returns the latest stock price for a ticker',
            'parameters': {
                'type': 'object',
                'properties': {'ticker': {'type': 'string'}},
                'required': ['ticker'],
            },
        },
    }
]

response = client.chat.completions.create(
    model='openai/gpt-4o-mini',
    messages=[{'role': 'user', 'content': 'What is AAPL trading at?'}],
    tools=tools,
    tool_choice='auto',
)

msg = response.choices[0].message
if msg.tool_calls:
    tc = msg.tool_calls[0]
    args = json.loads(tc.function.arguments)
    print('Calling tool:', tc.function.name, 'with', args)

import base64
from openai import OpenAI

client = OpenAI(
    base_url='https://openrouter.ai/api/v1',
    api_key='sk-or-...',
)

# Encode local image
with open('chart.png', 'rb') as f:
    b64 = base64.b64encode(f.read()).decode()

response = client.chat.completions.create(
    model='anthropic/claude-sonnet-5',   # vision-capable model
    messages=[
        {
            'role': 'user',
            'content': [
                {'type': 'text', 'text': 'What trend does this chart show?'},
                {
                    'type': 'image_url',
                    'image_url': {'url': f'data:image/png;base64,{b64}'},
                },
            ],
        }
    ],
)
print(response.choices[0].message.content)

// Node.js — using the openai npm package
import OpenAI from 'openai';

const client = new OpenAI({
  baseURL: 'https://openrouter.ai/api/v1',
  apiKey: process.env.OPENROUTER_API_KEY,
  defaultHeaders: {
    'HTTP-Referer': 'https://yourapp.com',
    'X-Title': 'My App',
  },
});

const response = await client.chat.completions.create({
  model: 'openai/gpt-4o-mini',
  messages: [{ role: 'user', content: 'Explain async/await in JavaScript.' }],
});
console.log(response.choices[0].message.content);
